var body = $input.first().json.body || {};
var url = body.url || '';

// Also check direct json properties and query params
if (!url) url = $input.first().json.url || '';
if (!url && $input.first().json.query) url = $input.first().json.query.url || '';

url = String(url).trim();

if (!url) {
  return [{json: {
    valid: false,
    success: false,
    error: 'Missing required parameter: url',
    job_id: ''
  }}];
}

// Extract job ID from LinkedIn URL
// Handles: /jobs/view/12345, /jobs/view/title-slug-12345, /jobs/view/12345?params
var jobIdMatch = url.match(/linkedin\.com\/jobs\/view\/(?:[^\/?]*[-\/])?(\d{8,})/);
if (!jobIdMatch) {
  jobIdMatch = url.match(/linkedin\.com\/jobs\/view\/(\d+)/);
}

if (!jobIdMatch) {
  return [{json: {
    valid: false,
    success: false,
    error: 'Invalid LinkedIn job URL. Expected format: https://linkedin.com/jobs/view/<job-id>',
    job_id: ''
  }}];
}

var jobId = jobIdMatch[1];
var normalizedUrl = 'https://www.linkedin.com/jobs/view/' + jobId;

console.log('Parsing job: ' + jobId);

return [{json: {valid: true, url: normalizedUrl, jobId: jobId}}];

var parsed = $input.first().json;
var urlData = $('Parse URL').first().json;
var jobId = urlData.jobId || '';
var sourceUrl = 'https://www.linkedin.com/jobs/view/' + jobId;

// Check if fetch/parse failed
if (!parsed.title && !parsed.description) {
  return [{json: {
    success: false,
    error: 'Failed to fetch or parse job page. LinkedIn may have blocked the request or the URL may be invalid.',
    job_id: jobId,
    source_url: sourceUrl
  }}];
}

var title = (parsed.title || '').trim();
var company = (parsed.company || '').trim();
var location = (parsed.location || '').trim();
var description = (parsed.description || '').replace(/\s+/g, ' ').trim();
var criteria = parsed.criteria || [];
var applyHtml = (parsed.applyHtml || '');

// Extract apply URL from HTML element
var applyUrl = '';
var hrefMatch = applyHtml.match(/href=["']([^"']+)["']/);
if (hrefMatch) {
  applyUrl = hrefMatch[1];
}

// Extract seniority from criteria
var seniorityLevel = '';
for (var i = 0; i < criteria.length; i++) {
  var c = (criteria[i] || '').toLowerCase().trim();
  if (c.includes('level') || c.includes('entry') || c.includes('senior') || c.includes('associate') || c.includes('director')) {
    seniorityLevel = (criteria[i] || '').trim();
    break;
  }
}

// Extract experience from description
var expText = 'Not specified';
var descLower = description.toLowerCase();
var expPatterns = [
  /(\d+)\s*\+\s*(?:years|yrs)/i,
  /(\d+)\s*[-\u2013to]+\s*(\d+)\s*(?:years|yrs)/i,
  /(?:minimum|at least|min\.?)\s*(\d+)\s*(?:years|yrs)/i,
  /(\d+)\s*(?:years|yrs)\s*(?:of)?\s*(?:experience|exp)/i
];
for (var p = 0; p < expPatterns.length; p++) {
  var match = descLower.match(expPatterns[p]);
  if (match) {
    expText = match[0].trim();
    break;
  }
}

console.log('Parsed: ' + title + ' at ' + company);

return [{json: {
  success: true,
  job_id: jobId,
  title: title,
  company: company,
  location: location,
  job_description: description,
  apply_url: applyUrl,
  experience: expText,
  seniority_level: seniorityLevel,
  criteria: criteria,
  source_url: sourceUrl
}}];
